"""
Our exception hierarchy:

* HTTPError
  x RequestError
    + TransportError
      - TimeoutException
        · ConnectTimeout
        · ReadTimeout
        · WriteTimeout
        · PoolTimeout
      - NetworkError
        · ConnectError
        · ReadError
        · WriteError
        · CloseError
      - ProtocolError
        · LocalProtocolError
        · RemoteProtocolError
      - ProxyError
      - UnsupportedProtocol
    + DecodingError
    + TooManyRedirects
  x HTTPStatusError
* InvalidURL
* CookieConflict
* StreamError
  x StreamConsumed
  x StreamClosed
  x ResponseNotRead
  x RequestNotRead
"""
import contextlib
import typing

if typing.TYPE_CHECKING:
    from ._models import Request, Response  # pragma: no cover


class HTTPError(Exception):
    """
    Base class for `RequestError` and `HTTPStatusError`.

    Useful for `try...except` blocks when issuing a request,
    and then calling `.raise_for_status()`.

    For example:

    '''
    try:
        response = httpx.get("https://www.example.com")
        response.raise_for_status()
    except httpx.HTTPError as exc:
        print(f"HTTP Exception for {exc.request.url} - {exc}")
    '''
    """

    def __init__(self, message: str) -> None:
        """Initialize an HTTPError with a message and no associated request.

        The `.request` attribute may be set later (for example via
        the `request_context` context manager) to provide access to the
        request that triggered this error.
        """
        super().__init__(message)
        self._request: typing.Optional["Request"] = None

    @property
    def request(self) -> "Request":
        """Return the Request associated with this error.

        Raises:
            RuntimeError: If no request has been associated with this error.
        """
        if self._request is None:
            raise RuntimeError("The .request property has not been set.")
        return self._request

    @request.setter
    def request(self, request: "Request") -> None:
        """Associate a Request with this error."""
        self._request = request


class RequestError(HTTPError):
    """
    Base class for all exceptions that may occur when issuing a `.request()`.
    """

    def __init__(
        self, message: str, *, request: typing.Optional["Request"] = None
    ) -> None:
        """Initialize a RequestError, optionally associating it with a Request.

        The request instance may be None when the error is raised; callers
        or a surrounding context manager can set `.request` later.
        """
        super().__init__(message)
        # At the point an exception is raised we won't typically have a request
        # instance to associate it with.
        #
        # The 'request_context' context manager is used within the Client and
        # Response methods in order to ensure that any raised exceptions
        # have a `.request` property set on them.
        self._request = request


class TransportError(RequestError):
    """
    Base class for all exceptions that occur at the level of the Transport API.
    """


# Timeout exceptions...


class TimeoutException(TransportError):
    """
    The base class for timeout errors.

    An operation has timed out.
    """


class ConnectTimeout(TimeoutException):
    """
    Timed out while connecting to the host.
    """


class ReadTimeout(TimeoutException):
    """
    Timed out while receiving data from the host.
    """


class WriteTimeout(TimeoutException):
    """
    Timed out while sending data to the host.
    """


class PoolTimeout(TimeoutException):
    """
    Timed out waiting to acquire a connection from the pool.
    """


# Core networking exceptions...


class NetworkError(TransportError):
    """
    The base class for network-related errors.

    An error occurred while interacting with the network.
    """


class ReadError(NetworkError):
    """
    Failed to receive data from the network.
    """


class WriteError(NetworkError):
    """
    Failed to send data through the network.
    """


class ConnectError(NetworkError):
    """
    Failed to establish a connection.
    """


class CloseError(NetworkError):
    """
    Failed to close a connection.
    """


# Other transport exceptions...


class ProxyError(TransportError):
    """
    An error occurred while establishing a proxy connection.
    """


class UnsupportedProtocol(TransportError):
    """
    Attempted to make a request to an unsupported protocol.

    For example issuing a request to `ftp://www.example.com`.
    """


class ProtocolError(TransportError):
    """
    The protocol was violated.
    """


class LocalProtocolError(ProtocolError):
    """
    A protocol was violated locally (e.g. by our implementation).
    """

    def __init__(self, message: str) -> None:
        """Initialize a LocalProtocolError with a descriptive message."""
        super().__init__(message)


class RemoteProtocolError(ProtocolError):
    """
    A protocol violation was observed from the remote peer.
    """

    def __init__(self, message: str) -> None:
        """Initialize a RemoteProtocolError with a descriptive message."""
        super().__init__(message)


class DecodingError(RequestError):
    """
    A response body could not be decoded (for example invalid gzip data).
    """

    def __init__(
        self,
        message: str,
        *,
        response: typing.Optional["Response"] = None,
        request: typing.Optional["Request"] = None,
    ) -> None:
        """Initialize a DecodingError, optionally including the Response.

        The response attribute, if provided, can be used by callers to
        inspect headers or the raw body associated with the decoding failure.
        """
        super().__init__(message, request=request)
        self.response = response


class TooManyRedirects(RequestError):
    """
    Raised when an excessive number of redirects has been encountered.
    """

    def __init__(
        self,
        message: str,
        *,
        response: typing.Optional["Response"] = None,
        request: typing.Optional["Request"] = None,
    ) -> None:
        """Initialize a TooManyRedirects error, optionally including the Response."""
        super().__init__(message, request=request)
        self.response = response


class HTTPStatusError(HTTPError):
    """
    Raised when a response has an HTTP status code that indicates error
    and `Response.raise_for_status()` is called.
    """

    def __init__(
        self,
        message: str,
        *,
        request: typing.Optional["Request"] = None,
        response: typing.Optional["Response"] = None,
    ) -> None:
        """Initialize an HTTPStatusError with optional request and response."""
        super().__init__(message)
        self._request = request
        self.response = response


class InvalidURL(ValueError):
    """
    Raised when an invalid URL is provided.
    """

    def __init__(self, message: str) -> None:
        """Initialize InvalidURL with a message describing the problem."""
        super().__init__(message)


class CookieConflict(ValueError):
    """
    Raised when there is a conflict setting cookies.
    """

    def __init__(self, message: str) -> None:
        """Initialize CookieConflict with a descriptive message."""
        super().__init__(message)


class StreamError(RuntimeError):
    """
    Base class for errors related to streaming request/response bodies.
    """

    def __init__(self, message: str) -> None:
        """Initialize a StreamError with a descriptive message."""
        super().__init__(message)


class StreamConsumed(StreamError):
    """
    Raised when attempting to read a stream that has already been consumed.
    """

    def __init__(self, message: str = "Stream has already been consumed.") -> None:
        """Initialize StreamConsumed with an optional message."""
        super().__init__(message)


class StreamClosed(StreamError):
    """
    Raised when attempting to operate on a closed stream.
    """

    def __init__(self, message: str = "Stream has been closed.") -> None:
        """Initialize StreamClosed with an optional message."""
        super().__init__(message)


class ResponseNotRead(StreamError):
    """
    Raised when attempting to access response content that hasn't been read.
    """

    def __init__(self, message: str = "Response content has not been read.") -> None:
        """Initialize ResponseNotRead with an optional message."""
        super().__init__(message)


class RequestNotRead(StreamError):
    """
    Raised when attempting to access request content that hasn't been read.
    """

    def __init__(self, message: str = "Request content has not been read.") -> None:
        """Initialize RequestNotRead with an optional message."""
        super().__init__(message)


@contextlib.contextmanager
def request_context(request: "Request"):
    """Context manager that sets the `.request` attribute on HTTP-related exceptions.

    Any exception raised within the context that has a `.request` attribute
    (i.e., subclasses of HTTPError / RequestError) will have its `.request`
    property set to the provided request before being re-raised.
    """
    try:
        yield
    except Exception:
        exc_info = typing.cast("BaseException", typing.cast(object, __import__("sys").exc_info()[1]))
        # If the exception is an HTTPError or RequestError, attach the request.
        if isinstance(exc_info, HTTPError):
            try:
                exc_info.request = request
            except Exception:
                # Be defensive: if setting fails, ignore and re-raise original.
                pass
        raise